appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const imgElement = document.getElementById('diagram-img');
    const textElement = document.getElementById('explanation-text');

    // 1. PARSE THE URL (or Base64 data)
    let url = "";
    if (model.queryData) {
      if (Array.isArray(model.queryData) && model.queryData.length > 0) {
        url = model.queryData[0].signedUrl || model.queryData[0].url || "";
      } else if (typeof model.queryData === 'object' && !Array.isArray(model.queryData)) {
        url = model.queryData.signedUrl || model.queryData.url || "";
      } else if (typeof model.queryData === 'string') {
        url = model.queryData;
      }
    }

    // 2. APPLY TO IMAGE
    if (url) {
      imgElement.src = url;
    } else {
      imgElement.alt = "Image data not found.";
    }

    // 3. APPLY TEXT
    if (model.explanation) {
      textElement.innerHTML = model.explanation;
    }
  });
});

